class Solution {
public:
    long long minSumSquareDiff(vector<int>& nums1, vector<int>& nums2, int k1, int k2) {
        vector<pair<int, int>> diff;
        for (int i = 0; i < nums1.size(); i++) {
            diff.push_back({abs(nums1[i] - nums2[i]), i});
        }
        sort(diff.begin(), diff.end());
        long long res = 0;
        for (int i = 0; i < diff.size(); i++) {
            int d = diff[i].first;
            if (k1 + k2 >= i + 1) {
                res += 0;
            } else {
                res += (long long)d * d;
            }
        }
        k1 += k2;
        for (int i = 0; i < diff.size(); i++) {
            int d = diff[i].first;
            if (k1 >= i + 1) {
                res -= (long long)d * d;
                res += 0;
            } else {
                int x = min(d, k1);
                res -= (long long)d * d;
                res += (long long)(d - x) * (d - x);
                k1 -= x;
            }
        }
        return res;
    }
};
```
